local function pQ()
    local sW={}
    local sX={}
    local sY=false

    local function sZ(self,da)
        assert(typeof(da)=="function","Can only subscribe to signals with a function.")
        local nD={callback=da,disconnected=false}
        if sY and not sW[da] then
            sX[da]=nD
        end
        sW[da]=nD
        local function oy()
            assert(not nD.disconnected,"Listeners can only be disconnected once.")
            nD.disconnected=true
            sW[da]=nil
            sX[da]=nil
        end
        return oy
    end

    local function s_(self,...)
        sY=true
        for da,nD in pairs(sW) do
            if not nD.disconnected and not sX[da] then
                da(...)
            end
        end
        sY=false
        for da,ev in pairs(sX) do
            sX[da]=nil
        end
    end

    return {subscribe=sZ,fire=s_}
end
return pQ
